import type { StudyPlotInfo } from '../types';

interface StyleRecord {
  [key: string]: unknown;
  location?: unknown;
}

interface AutoscaleInfo {
  min: number;
  max: number;
}

function resolveLocationValue(style: StyleRecord | undefined): unknown {
  if (!style || style.location === undefined || style.location === null) {
    // Mirror the production crash signature seen in Chart Host reducers.
    throw new TypeError(
      "Cannot read properties of undefined (reading 'value')",
    );
  }
  const location = style.location as unknown;
  if (
    typeof location === 'object' &&
    location !== null &&
    'value' in (location as Record<string, unknown>)
  ) {
    const candidate = (location as { value?: unknown }).value;
    if (typeof candidate === 'function') return candidate();
    return candidate;
  }
  return location;
}

function resolveVisualPlotTypeValue(plot: StudyPlotInfo): unknown {
  const visualType = (plot as unknown as Record<string, unknown>).plottype;
  if (visualType === undefined || visualType === null) {
    // Mirrors reducer/runtime signatures where enum lookup receives
    // `undefined` and immediately throws with this exact message.
    throw new Error('Value is undefined');
  }
  if (
    typeof visualType === 'object' &&
    visualType !== null &&
    'value' in (visualType as Record<string, unknown>)
  ) {
    const candidate = (visualType as { value?: unknown }).value;
    if (typeof candidate === 'function') return candidate();
    return candidate;
  }
  return visualType;
}

function resolveVisualCharValue(plot: StudyPlotInfo): unknown {
  const visualChar = (plot as unknown as Record<string, unknown>).char;
  if (
    visualChar === undefined ||
    visualChar === null ||
    String(visualChar).trim() === ''
  ) {
    throw new Error('Value is undefined');
  }
  return visualChar;
}

/**
 * Chart Host-shaped autoscale reducer fragment.
 *
 * Only models the contract surface that tends to crash transpiled indicators:
 * visual plot style lookup (`styles[plot.id]`) and location access for
 * char/shape-style plots.
 */
export function applyPlotToPrecalculatedAutoscaleInfo(
  plot: StudyPlotInfo,
  style: StyleRecord | undefined,
  point: unknown,
  autoscale: AutoscaleInfo,
): void {
  if (plot.type === 'shapes') {
    // Side-effect is contract validation; value unused by the harness.
    resolveVisualPlotTypeValue(plot);
    resolveLocationValue(style);
  } else if (plot.type === 'chars') {
    resolveVisualCharValue(plot);
    resolveLocationValue(style);
  }
  const n = Number(point);
  if (!Number.isFinite(n)) return;
  autoscale.min = Math.min(autoscale.min, n);
  autoscale.max = Math.max(autoscale.max, n);
}

/**
 * Chart Host-shaped dependency reducer fragment used by view updates.
 */
export function dependsOnSeriesData(
  plot: StudyPlotInfo,
  style: StyleRecord | undefined,
): boolean {
  if (plot.type === 'shapes') {
    resolveVisualPlotTypeValue(plot);
    resolveLocationValue(style);
  } else if (plot.type === 'chars') {
    resolveVisualCharValue(plot);
    resolveLocationValue(style);
  }
  return plot.type !== 'hline';
}
